import "@/App.css";
import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
import axios from "axios";
import { Toaster } from "@/components/ui/sonner";

// ======================
// NEW LAYER PAGES
// ======================
import LandingPage from "@/pages/LandingPage";
import SchoolProfilePage from "@/pages/SchoolProfilePage";

// ======================
// AUTH / CORE PAGES
// ======================
import LoginPage from "@/pages/LoginPage";
import RegisterPage from "@/pages/RegisterPage";

// ======================
// DASHBOARD LAYOUT
// ======================
import DashboardLayout from "@/components/layouts/DashboardLayout";

// ======================
// MODULE PAGES
// ======================
import Dashboard from "@/pages/Dashboard";
import StudentsPage from "@/pages/StudentsPage";
import StaffPage from "@/pages/StaffPage";
import FeesPage from "@/pages/FeesPage";
import AttendancePage from "@/pages/AttendancePage";
import ExamsPage from "@/pages/ExamsPage";
import TimetablePage from "@/pages/TimetablePage";
import InventoryPage from "@/pages/InventoryPage";

// ======================
// PORTALS
// ======================
import StudentPortal from "@/pages/StudentPortal";
import TeacherPortal from "@/pages/TeacherPortal";
import FinancePortal from "@/pages/FinancePortal";
import SecretaryPortal from "@/pages/SecretaryPortal";

// ======================
// ADMIN
// ======================
import SuperAdminDashboard from "@/pages/SuperAdminDashboard";
import AnnouncementsPage from "@/pages/AnnouncementsPage";

// ======================
// DEBUG
// ======================
import DataExplorer from "@/pages/DataExplorer";

// ======================
// BACKEND CONFIG
// ======================
const BACKEND_URL = process.env.REACT_APP_BACKEND_URL;
export const API = `${BACKEND_URL}/api`;

// ======================
// AUTH SERVICE
// ======================
export const authService = {
  getToken: () => localStorage.getItem("token"),
  getUser: () => {
    const user = localStorage.getItem("user");
    return user ? JSON.parse(user) : null;
  },
  setAuth: (token, user) => {
    localStorage.setItem("token", token);
    localStorage.setItem("user", JSON.stringify(user));
  },
  clearAuth: () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
  },
  isAuthenticated: () => !!localStorage.getItem("token"),
};

// ======================
// AXIOS CLIENT
// ======================
export const apiClient = axios.create({
  baseURL: API,
});

// attach token to every request
apiClient.interceptors.request.use((config) => {
  const token = authService.getToken();

  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }

  return config;
});

// 🔥 GLOBAL ERROR HANDLER (IMPORTANT FIX)
apiClient.interceptors.response.use(
  (response) => response,
  (error) => {
    // If token is invalid or expired
    if (error?.response?.status === 401) {
      console.warn("Invalid/expired token detected. Clearing session...");

      authService.clearAuth();

      // force login reset
      window.location.href = "/login";
    }

    return Promise.reject(error);
  }
);
// ======================
// ROUTE GUARD
// ======================
const ProtectedRoute = ({ children }) => {
  return authService.isAuthenticated() ? children : <Navigate to="/login" />;
};

// ======================
// APP
// ======================
function App() {
  return (
    <div className="App">
      <BrowserRouter>
        <Routes>

          {/* 🔵 LAYER 1 — PUBLIC LANDING */}
          <Route path="/" element={<LandingPage />} />

          {/* 🟡 LAYER 2 — SCHOOL SETUP */}
          <Route path="/setup-school" element={<SchoolProfilePage />} />

          {/* AUTH */}
          <Route path="/login" element={<LoginPage />} />
          <Route path="/register" element={<RegisterPage />} />

          {/* 🔴 MAIN APP (ONLY AFTER SCHOOL EXISTS) */}
<Route
  path="/app"
  element={
    <ProtectedRoute>
      <DashboardLayout />
    </ProtectedRoute>
  }
>
  <Route index element={<Navigate to="dashboard" />} />
  <Route path="dashboard" element={<Dashboard />} />

  {/* CORE MODULES */}
  <Route path="students" element={<StudentsPage />} />
  <Route path="staff" element={<StaffPage />} />
  <Route path="fees" element={<FeesPage />} />
  <Route path="attendance" element={<AttendancePage />} />
  <Route path="exams" element={<ExamsPage />} />
  <Route path="timetable" element={<TimetablePage />} />
  <Route path="inventory" element={<InventoryPage />} />

  {/* PORTALS */}
  <Route path="student-portal" element={<StudentPortal />} />
  <Route path="teacher-portal" element={<TeacherPortal />} />
  <Route path="finance-portal" element={<FinancePortal />} />
  <Route path="secretary-portal" element={<SecretaryPortal />} />

  {/* ADMIN */}
  <Route path="super-admin" element={<SuperAdminDashboard />} />
  <Route path="announcements" element={<AnnouncementsPage />} />

  {/* DEBUG */}
  <Route path="debug" element={<DataExplorer />} />
</Route>

        </Routes>
      </BrowserRouter>

      <Toaster position="top-right" />
    </div>
  );
}

export default App;
